import zipfile, re
def extract(fn):
    z=zipfile.ZipFile(fn)
    xml=z.read('word/document.xml').decode('utf-8','ignore')
    text=re.sub(r'<[^>]+>',' ',xml)
    for a,b in [('&amp;','&'),('&lt;','<'),('&gt;','>'),('&quot;','\"'),('&#39;',\"'\"),('&apos;',\"'\")]:
        text=text.replace(a,b)
    return re.sub(r'[ \t]+',' ',text)

t=extract('second-lien-credit-agreement.docx')
# Total Leverage covenant
for m in re.finditer(r'Total Leverage', t):
    seg=t[m.start():m.start()+160]
    if '6.50' in seg or 'not to exceed' in seg or 'shall not' in seg or 'ratio' in seg:
        print('---',m.start())
        print(t[m.start():m.start()+500])
        print()
