import zipfile, re
def extract(fn):
    z=zipfile.ZipFile(fn)
    xml=z.read('word/document.xml').decode('utf-8','ignore')
    text=re.sub(r'<[^>]+>',' ',xml)
    for a,b in [('&amp;','&'),('&lt;','<'),('&gt;','>'),('&quot;','\"'),('&#39;',\"'\"),('&apos;',\"'\")]:
        text=text.replace(a,b)
    return re.sub(r'[ \t]+',' ',text)
t=extract('second-lien-credit-agreement.docx')
for kw in ['102.00','101.00','102.0','101.0','prepayment premium','Prepayment Premium','Premium','year one','year two','first anniversary','second anniversary','non-call','Non-Call']:
    for m in re.finditer(re.escape(kw),t):
        seg=t[m.start():m.start()+200]
        if any(x in seg for x in ['102','101','premium','Premium','anniversary','call']):
            print(f'--- {kw} at {m.start()}:', seg[:220])
            break
